%[text] # 例6.17（消失モーメント）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2025b
%[text] ## 準備
isVerbose = false;
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example06_17"; % mfilename
%%
waveinfo('db') %[output:0db40cbf]

% DB1 (Haar)
figure(1) %[output:3199ac61]
[~,~,f0,f1] = wfilters('db1') %[output:0f1af776] %[output:54cc606c]
[hw,fw] = zerophase(f0,1,1024,"whole");

z = roots(f0);
p = 0;

%plot3(cos(fw),sin(fw),hw)
plot(cos(fw),sin(fw),'--','Color',[0.5 0.5 0.5],'LineWidth',1) %[output:3199ac61]
hold on %[output:3199ac61]
plot(real(z),imag(z),'o','Color','black') %[output:3199ac61]
text(real(z(1))+0.05,imag(z(1)),'1','FontSize',12) %[output:3199ac61]
plot(real(p),imag(p),'x','Color','black') %[output:3199ac61]
hold off %[output:3199ac61]
xlabel("$\Re(F_0(z))$","Interpreter","latex") %[output:3199ac61]
ylabel("$\Im(F_0(z))$","Interpreter","latex") %[output:3199ac61]
%view(35,40)
grid %[output:3199ac61]
axis equal %[output:3199ac61]
axis([-1.2 1.2 -1.2 1.2]) %[output:3199ac61]

ax = gca;
ax.FontSize = 12; %[output:3199ac61]
ax.LineWidth =1; %[output:3199ac61]
ax.XTick = -1:0.5:1; %[output:3199ac61]
ax.YTick = -1:0.5:1; %[output:3199ac61]

hfig = gcf;

exportgraphics(hfig,fullfile(resfolder,"fig06-14a.png"),'ColorSpace','gray') %[output:3199ac61]

%%

% DB2
figure(2) %[output:550cb010]
[~,~,f0,f1] = wfilters('db2') %[output:894f28f5] %[output:1597047b]
[hw,fw] = zerophase(f0,1,1024,"whole");

z = roots(f0);
p = 0;

%plot3(cos(fw),sin(fw),hw)
plot(cos(fw),sin(fw),'--','Color',[0.5 0.5 0.5],'LineWidth',1) %[output:550cb010]
hold on %[output:550cb010]
plot(real(z),imag(z),'o','Color','black') %[output:550cb010]
text(real(z(1))+0.05,imag(z(1)),'2','FontSize',12) %[output:550cb010]
plot(real(p),imag(p),'x','Color','black') %[output:550cb010]
text(real(p(1))+0.05,imag(p(1)),'3','FontSize',12) %[output:550cb010]
hold off %[output:550cb010]
xlabel("$\Re(F_0(z))$","Interpreter","latex") %[output:550cb010]
ylabel("$\Im(F_0(z))$","Interpreter","latex") %[output:550cb010]
%view(35,40)
grid %[output:550cb010]
axis equal %[output:550cb010]
axis([-1.2 1.2 -1.2 1.2]) %[output:550cb010]

ax = gca;
ax.FontSize = 12; %[output:550cb010]
ax.LineWidth = 1; %[output:550cb010]
ax.XTick = -1:0.5:1; %[output:550cb010]
ax.YTick = -1:0.5:1; %[output:550cb010]

hfig = gcf;

exportgraphics(hfig,fullfile(resfolder,"fig06-14b.png"),'ColorSpace','gray') %[output:550cb010]
%%
2^(-5/2)*conv(conv([1 1],[1 1]),[1+sqrt(3) 1-sqrt(3)]) %[output:6ccd420d]
2^(-5/2)*conv(conv([1 -1],[1 -1]),[1-sqrt(3) -1-sqrt(3)]) %[output:3e1ae567]
